import{_ as e,o as t,c as l,a5 as r}from"./chunks/framework.DiSld4Xn.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"S6-Go/阶段15-性能优化实战.md","filePath":"S6-Go/阶段15-性能优化实战.md","lastUpdated":1780660866000}'),a={name:"S6-Go/阶段15-性能优化实战.md"};function n(i,o,c,s,d,p){return t(),l("div",null,[...o[0]||(o[0]=[r('<h2 id="⚡-阶段十五-性能优化实战与调优案例" tabindex="-1">⚡ 阶段十五：性能优化实战与调优案例 <a class="header-anchor" href="#⚡-阶段十五-性能优化实战与调优案例" aria-label="Permalink to &quot;⚡ 阶段十五：性能优化实战与调优案例&quot;">​</a></h2><h3 id="_15-1-cpu-与内存调优" tabindex="-1">15.1 CPU 与内存调优 <a class="header-anchor" href="#_15-1-cpu-与内存调优" aria-label="Permalink to &quot;15.1 CPU 与内存调优&quot;">​</a></h3><h4 id="q59-线上服务频繁-full-gc-如何排查与优化" tabindex="-1">Q59: 线上服务频繁 Full GC 如何排查与优化？ <a class="header-anchor" href="#q59-线上服务频繁-full-gc-如何排查与优化" aria-label="Permalink to &quot;Q59: 线上服务频繁 Full GC 如何排查与优化？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：GC 触发阈值、内存分配模式、对象生命周期、<code>GOGC</code> 调整。</p><p><strong>💡 记忆关键词</strong>：gctrace 追踪、pprof 分析、sync.Pool 复用、GOGC 调参</p><p><strong>答案要点</strong>：</p><ul><li><strong>排查</strong>：使用 <code>go tool pprof -alloc_space</code> 查看内存分配热点；开启 <code>GODEBUG=gctrace=1</code> 观察 GC 频率与暂停时间。</li><li><strong>优化策略</strong>： <ol><li>减少短期对象分配（复用 buffer、<code>sync.Pool</code>）。</li><li>避免大对象频繁创建（如大切片、大 Map）。</li><li>调整 <code>GOGC</code> 参数（默认 100，可适当调高至 200~500 降低 GC 频率，但会增加内存占用）。</li><li>使用 <code>debug.FreeOSMemory()</code> 主动释放内存（谨慎使用，可能引发 STW）。</li></ol></li></ul><h4 id="q60-如何优化高并发下的-json-序列化性能" tabindex="-1">Q60: 如何优化高并发下的 JSON 序列化性能？ <a class="header-anchor" href="#q60-如何优化高并发下的-json-序列化性能" aria-label="Permalink to &quot;Q60: 如何优化高并发下的 JSON 序列化性能？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：反射开销、预编译、<code>jsoniter</code>/<code>sonic</code>、结构体标签。</p><p><strong>💡 记忆关键词</strong>：反射开销、sonic/jit、easyjson 生成、omitempty 精简</p><p><strong>答案要点</strong>：</p><ul><li>标准库 <code>encoding/json</code> 使用反射，性能较低。</li><li><strong>优化方案</strong>： <ol><li>使用 <code>json-iterator/go</code> 或字节跳动开源的 <code>sonic</code>（基于 JIT 编译，性能提升 3~10 倍）。</li><li>结构体字段使用 <code>json:&quot;name,omitempty&quot;</code> 减少冗余。</li><li>对热点路径手动序列化或使用代码生成工具（如 <code>easyjson</code>）。</li><li>避免在循环中重复 <code>json.Marshal</code>，预编译 Schema 或使用池化 Encoder。</li></ol></li></ul><h3 id="_15-2-网络与-io-优化" tabindex="-1">15.2 网络与 IO 优化 <a class="header-anchor" href="#_15-2-网络与-io-优化" aria-label="Permalink to &quot;15.2 网络与 IO 优化&quot;">​</a></h3><h4 id="q61-如何优化-go-服务的-tcp-连接数与文件描述符限制" tabindex="-1">Q61: 如何优化 Go 服务的 TCP 连接数与文件描述符限制？ <a class="header-anchor" href="#q61-如何优化-go-服务的-tcp-连接数与文件描述符限制" aria-label="Permalink to &quot;Q61: 如何优化 Go 服务的 TCP 连接数与文件描述符限制？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：<code>ulimit</code>、连接池、TIME_WAIT 处理、内核参数调优。</p><p><strong>💡 记忆关键词</strong>：ulimit 调高、连接池复用、Keep-Alive、TIME_WAIT 优化</p><p><strong>答案要点</strong>：</p><ul><li>系统层：调整 <code>ulimit -n</code>（默认 1024，生产建议 65535+）；优化 <code>net.ipv4.tcp_tw_reuse</code>、<code>tcp_fin_timeout</code>。</li><li>应用层： <ol><li>使用连接池复用 HTTP/gRPC 连接（<code>http.Transport.MaxIdleConns</code>）。</li><li>避免频繁短连接，启用 Keep-Alive。</li><li>监控 <code>netstat</code> 状态，排查 <code>CLOSE_WAIT</code> 泄漏（代码未正确 Close）。</li></ol></li></ul><hr>',22)])])}const u=e(a,[["render",n]]);export{_ as __pageData,u as default};
